#!/usr/bin/env bash
# workflow-2.sh — 价值投资工作流（选股 → 估值 → 安全边际 → 持有/卖出） SOP walkthrough for 个人投资理财.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="个人投资理财"
WORKFLOW="价值投资工作流（选股 → 估值 → 安全边际 → 持有/卖出）"

usage() {
  cat <<EOF
workflow-2.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-2.sh             # interactive
  ./workflow-2.sh --dry-run
  ./workflow-2.sh --json
  ./workflow-2.sh --explain
  ./workflow-2.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "价值投资工作流（选股 → 估值 → 安全边际 → 持有/卖出）" 工作流。

一句话: 从「我想自己选股票而非买指数」到「以显著低于内在价值的价格买入并理解的好生意、长期持有、按 thesis 卖出」—— 价值派把股票当「企业的一小块所有权」而非可炒作的纸片。对照 Workflow 3 的被动派：本派赌「主动选股能跑赢」（与被动派的核心 canon 分歧）。

入门 SOP 共 8 步, 失败模式自检 5 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**划能力圈 (circle of competence)**：只研究你真正看得懂商业模式/赚钱逻辑/风险的行业。Buffett：「圈的大小不重要，知道边界在哪才重要。」(evidence: [T03-S014])"
  "**建选股池 / 筛选**：在能力圈内用筛选器（GuruFocus F-Score/Z-Score、理杏仁 PE/PB 历史分位）缩小到少数候选。(evidence: [T03-S015])"
  "**商业理解（看生意不看股价）**：读财报/年报/股东信，理解护城河、ROE 质量（DuPont 拆解防杠杆虚高）、自由现金流（比会计利润难造假）、管理层。(evidence: [T03-S014])"
  "**估值（内在价值 / DCF / 相对）**：Damodaran 路线——把「故事」翻译成「数字」（增长率/利润率/再投资），DCF 折现求内在价值 + 相对估值（同业倍数）交叉；DCF 是 sensitivity 工具不是精确科学，重区间和逻辑。(evidence: [T03-S015])"
  "**安全边际检验（再买）**：只在**价格显著低于内在价值**时买入，用折扣吸收判断误差与坏运气（Graham 的稳健投资中心概念）。(evidence: [T03-S014])"
  "**仓位 / 集中度**：决定单一标的占组合多少（价值派偏集中但有上限，控单笔最大损失）。(evidence: [T03-S014])"
  "**持有 + 跟踪 thesis**：长期持有，定期复核「当初买入的理由还成立吗」（护城河有没有被侵蚀、基本面有没有变）。(evidence: [T03-S014])"
  "**卖出纪律（thesis 驱动）**：卖出触发 = ① thesis 被证伪（基本面恶化）② 估值远超内在价值 ③ 发现明显更好的机会 ④ 当初买入的错误被发现。**不**因股价短期波动卖。(evidence: [T03-S014])"
)
declare -a FAILURE_MODES=(
  "**能力圈外选股**：研究看不懂的热门行业，本质赌方向。自检：你能用一句话讲清这家公司怎么赚钱、护城河是什么吗？"
  "**把 P/E 低当便宜**：忽略「便宜可以更便宜」「低 P/E = 价值陷阱」。自检：你估了内在价值、确认是 price 跌而非 value 跌了吗？"
  "**没有安全边际就买**：好公司付高价 = 坏投资。自检：现价相对你估的内在价值有没有显著折扣？"
  "**thesis 破了还死扛**：护城河被侵蚀、基本面恶化却因锚定（成本价）/沉没成本不卖。自检：当初买入的理由今天还成立吗？"
  "**用价格而非 thesis 做买卖**：涨了落袋、跌了恐慌，处置效应。自检：这笔卖出是 thesis 驱动还是情绪驱动？"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-2-walkthrough"
fi
